#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_NODES 100002

typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

Node* adj[MAX_NODES];
bool check;
int degree[MAX_NODES];

void add_edge(int u, int v) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->vertex = v;
    newNode->next = adj[u];
    adj[u] = newNode;
}

void dfs(int node, int par, int s, int sum) {
    s += node;
    Node* current = adj[node];
    while (current != NULL) {
        int v = current->vertex;
        if (v != par) {
            dfs(v, node, s, sum);
        }
        current = current->next;
    }
    if (par != -1 && degree[node] == 1) {
        check |= (s == sum);
    }
    s -= node;
}

int main() {
    int n, target_sum;
    scanf("%d %d", &n, &target_sum);

    // Edge case
    if (n == 1) {
        if (target_sum == 1) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        return 0;
    }

    check = false;
    memset(degree, 0, sizeof(degree));

    // Initialize adjacency list
    for (int i = 0; i <= n; i++) {
        adj[i] = NULL;
    }

    // Read edges and build adjacency list
    for (int i = 1; i < n; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        degree[u]++;
        degree[v]++;
        add_edge(u, v);
        add_edge(v, u);
    }

    // Start DFS from node 1
    dfs(1, -1, 0, target_sum);

    // Output the result
    printf("%s\n", check ? "YES" : "NO");

    // Free the allocated memory
    for (int i = 0; i <= n; i++) {
        Node* current = adj[i];
        while (current != NULL) {
            Node* temp = current;
            current = current->next;
            free(temp);
        }
    }

    return 0;
}

