import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    static List<Integer>[] adj;
    static boolean check;
    static int[] degree;

    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int targetSum = sc.nextInt();

        // Check if N is within the allowed range
        if (n < 1 || n > 100000) {
            throw new IllegalArgumentException("N must be between 1 and 100000");
        }

        // Edge case
        if (n == 1) {
            if (targetSum == 1) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
            return;
        }

        check = false;
        adj = new ArrayList[n + 1];
        degree = new int[n + 1];

        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 1; i < n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            degree[u]++;
            degree[v]++;
            adj[u].add(v);
            adj[v].add(u);
        }

        dfs(1, -1, 0, targetSum);
        System.out.println(check ? "YES" : "NO");
    }

    static void dfs(int node, int par, int s, int sum) {
        s += node;
        for (int v : adj[node]) {
            if (v != par) {
                dfs(v, node, s, sum);
            }
        }
        if (par != -1 && degree[node] == 1) {
            check |= (s == sum);
        }
        s -= node;
    }
}

