const readline = require('readline');

const adj = [];
let check = false;
const degree = [];

function dfs(node, par, currentSum, targetSum) {
    currentSum += node;
    for (let v of adj[node]) {
        if (v !== par) {
            dfs(v, node, currentSum, targetSum);
        }
    }
    if (par !== -1 && degree[node] === 1) {
        check |= (currentSum === targetSum);
    }
    currentSum -= node;
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let n = 0, targetSum = 0;
    let edgeCount = 0;

    rl.on('line', (line) => {
        if (n === 0) {
            [n, targetSum] = line.trim().split(' ').map(Number);
            for (let i = 0; i <= n; i++) {
                adj.push([]);
                degree.push(0);
            }
        } else {
            const [u, v] = line.trim().split(' ').map(Number);
            degree[u]++;
            degree[v]++;
            adj[u].push(v);
            adj[v].push(u);
            edgeCount++;
            if (edgeCount === n - 1) {
                rl.close();
            }
        }
    });

    rl.on('close', () => {
        // Edge case: Single node tree
        if (n === 1) {
            if (targetSum === 1) {
                console.log("YES");
            } else {
                console.log("NO");
            }
            process.exit(0);
        }

        dfs(1, -1, 0, targetSum);
        console.log(check ? "YES" : "NO");
        process.exit(0);
    });
}

// Run the main function
main();
